var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"LOTUS_ADMIN_NULL_NULL","text":{"KOREA":"낚싯대를 우물에 연결하는 것까진 성공했어.","JPN":"釣り竿を井戸に繋げるまでは上手くいった。","ENG":"The Fishing Rod has been successfully connected to the Well.","TWN":"釣魚竿已經成功連接到井裡了。"},"stage":{"bg":"COUNTERSIDE_BASE","bgm":"THEMA_DIVE_BOTTOM","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LOTUS_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE"},{"id":"L3_1","type":"dialog","speaker":"LOTUS_ADMIN_NULL_NULL","text":{"KOREA":"남은 건 잠망경이 확보한 시간 좌표를 낚싯대와 동기화 시켜서 패러독스를 끌어올리는 것 뿐이야.","JPN":"あとは、潜望鏡が確保した時間座標を釣り竿に同期化して、パラドックスを引き上げるだけだよ。","ENG":"All that's left is to secure the time coordinates with the Periscope, sync it with the Fishing Rod, and pull Paradox out from there.","TWN":"剩下的就是將潛望鏡獲取到的時間座標與釣魚竿同步，然後把悖論拉回來。"},"stage":{"bg":"COUNTERSIDE_BASE","bgm":"THEMA_DIVE_BOTTOM","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LOTUS_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"좀 더 기다려야 하네.","JPN":"もう少し時間が必要だ。","ENG":"We will have to wait a little longer.","TWN":"還要再等一會。"},"stage":{"bg":"COUNTERSIDE_BASE","bgm":"THEMA_DIVE_BOTTOM","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LOTUS_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"아직 좌표로 삼을만한 에너지 신호가 관측되지 않았어.","JPN":"まだ座標として使えるほどのエネルギー信号が観測されていない。","ENG":"No energy signals that can be used as coordinates have been observed yet.","TWN":"還沒有觀測到可以作為座標的能量訊號。"},"stage":{"bg":"COUNTERSIDE_BASE","bgm":"THEMA_DIVE_BOTTOM","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LOTUS_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"LOTUS_ADMIN_NULL_NULL","text":{"KOREA":"잠깐, 갑자기 전파가 불안정해졌네.","JPN":"ちょっと、急に電波が不安定になったよ。","ENG":"Wait. The transmission signal is suddenly unstable.","TWN":"等一下，訊號突然變得不穩定了。"},"stage":{"bg":"COUNTERSIDE_BASE","bgm":"THEMA_DIVE_BOTTOM","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LOTUS_ADMIN_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}},"sfx":"FX_CUTSCEN_NOISE"},{"id":"L9_1","type":"dialog","speaker":"LOTUS_ADMIN_NULL_NULL","text":{"KOREA":"위성에 침식 폭풍 같은 건 관측되지 않는데… 응?","JPN":"衛星に侵食の嵐は観測されてないはず……うん？","ENG":"The satellite isn't picking up on any Corruption storms... Hmm?","TWN":"衛星上沒有觀測到侵蝕風暴……嗯？"},"stage":{"bg":"COUNTERSIDE_BASE","bgm":"THEMA_DIVE_BOTTOM","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LOTUS_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"LOTUS_ADMIN_NULL_NULL","text":{"KOREA":"조심해! 지금 그쪽으로 엄청 많은 숫자의…!","JPN":"気をつけて！　今そっちに向かってかなり多くの……！","ENG":"Watch out! There are a lot of– headed–!","TWN":"小心！有很多……往你那邊……！"},"stage":{"bg":"COUNTERSIDE_BASE","bgm":"THEMA_DIVE_BOTTOM","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LOTUS_ADMIN_NULL_NULL","face":"UNIT_HATE"},"R":null}},"sfx":"FX_CUTSCEN_PHONE"},{"id":"L13_1","type":"dialog","speaker":"FATIMA_LOTUS_NULL_NULL","text":{"KOREA":"통신이 강제로 끊어졌군요.","JPN":"通信が強制的に途切れてしまいましたね。","ENG":"Comms have been cut off.","TWN":"通訊被強制中斷了。"},"stage":{"bg":"COUNTERSIDE_BASE","bgm":"THEMA_DIVE_BOTTOM","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":{"char_id":"FATIMA_LOTUS_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L14_1","type":"dialog","speaker":"SERGEANT_GRONIA_NULL_NULL","text":{"KOREA":"침식 폭풍은 아니라고 했어요. 그렇다면…","JPN":"侵食の嵐ではないようです。ということは……","ENG":"She said it wasn't a Corruption storm. Then...","TWN":"如果這不是侵蝕風暴，那麼……"},"stage":{"bg":"COUNTERSIDE_BASE","bgm":"THEMA_DIVE_BOTTOM","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SERGEANT_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"FATIMA_LOTUS_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L16_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"…누군가 우릴 방해하고 있단 뜻이군.","JPN":"……誰かに邪魔されているってわけか。","ENG":"...It means that someone has come to stop us.","TWN":"……這就表示有人在阻撓我們。"},"stage":{"bg":"COUNTERSIDE_BASE","bgm":"THEMA_DIVE_BOTTOM","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SERGEANT_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"FATIMA_LOTUS_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L20_1","type":"dialog","speaker":"SERGEANT_GRONIA_NULL_NULL","text":{"KOREA":"……!","JPN":"……！","ENG":"...!","TWN":"……！"},"stage":{"bg":"COUNTERSIDE_BASE","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":{"char_id":"SERGEANT_GRONIA_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L21_1","type":"dialog","speaker":"SERGEANT_GRONIA_NULL_NULL","text":{"KOREA":"위쪽이에요!","JPN":"上です！","ENG":"Above us!","TWN":"在上面！"},"stage":{"bg":"COUNTERSIDE_BASE","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":{"char_id":"SERGEANT_GRONIA_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L23_1","type":"dialog","speaker":"FATIMA_LOTUS_NULL_NULL","text":{"KOREA":"관리자님! 이쪽으로!","JPN":"最高管理者！　こちらへ！","ENG":"Administrator! This way!","TWN":"管理者！這邊！"},"stage":{"bg":"COUNTERSIDE_BASE","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"FATIMA_LOTUS_NULL_NULL","face":"UNIT_SERIOUS"},"R":{"char_id":"SERGEANT_GRONIA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L27_1","type":"dialog","speaker":"FATIMA_LOTUS_NULL_NULL","text":{"KOREA":"괜찮으십니까?","JPN":"大丈夫ですか？","ENG":"Are you okay?","TWN":"你還好嗎?"},"stage":{"bg":"COUNTERSIDE_BASE","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"FATIMA_LOTUS_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"…고맙네. 하마터면 머리에 직격 할 뻔했군.","JPN":"……ありがとう。危うく頭に直撃するところだった。","ENG":"...Thank you. That almost hit me right on my head.","TWN":"……謝謝。差點就被直接擊中頭部了。"},"stage":{"bg":"COUNTERSIDE_BASE","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"FATIMA_LOTUS_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"SERGEANT_GRONIA_NULL_NULL","text":{"KOREA":"방금 떨어진 건 뭐죠? 농구공만 한 크기였는데.","JPN":"今のはなんです？　バスケットボールぐらいのサイズでしたよ。","ENG":"What was that? It was the size of a basketball.","TWN":"剛剛掉下來的是什麼？有籃球那麼大……"},"stage":{"bg":"COUNTERSIDE_BASE","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SERGEANT_GRONIA_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"FATIMA_LOTUS_NULL_NULL","text":{"KOREA":"땅으로 순식간에 스며들어서 정확히는 못 봤지만…","JPN":"一瞬で地面に消えていったせいで、はっきり見ることはできませんでしたが……","ENG":"It quickly seeped into the ground, so I couldn't get a clear view of it, but...","TWN":"在一瞬間就滲入地面了，沒能看清楚……"},"stage":{"bg":"COUNTERSIDE_BASE","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"FATIMA_LOTUS_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":"FATIMA_LOTUS_NULL_NULL","text":{"KOREA":"…이건 침식 종양의 일종 같습니다.","JPN":"……これは侵食腫瘍の一種かと。","ENG":"...it seems like a type of Corrupted Tumor.","TWN":"……那似乎是一種侵蝕性的腫瘤。"},"stage":{"bg":"COUNTERSIDE_BASE","bgm":"THEMA_DIVE_EATER","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"FATIMA_LOTUS_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":null}}},{"id":"L34_1","type":"dialog","speaker":"SERGEANT_GRONIA_NULL_NULL","text":{"KOREA":"땅이 검게 물들고 있어요.","JPN":"地面が黒く染まってます。","ENG":"The ground is turning black.","TWN":"地面被染成了黑色的了……"},"stage":{"bg":"COUNTERSIDE_BASE","bgm":"THEMA_DIVE_EATER","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"FATIMA_LOTUS_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SERGEANT_GRONIA_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L35_1","type":"dialog","speaker":"SERGEANT_GRONIA_NULL_NULL","text":{"KOREA":"제가 침식학을 배운 적은 없지만, 이 위에 계속 서있는 건 엄청 위험하지 않을까요?","JPN":"私、侵食学には詳しくないけど、この場所にいるのは危険では？","ENG":"I never studied Corruption, but won't it be dangerous for us to stay above it?","TWN":"我雖然沒學過侵蝕學，但我們站在上面不會很危險嗎？"},"stage":{"bg":"COUNTERSIDE_BASE","bgm":"THEMA_DIVE_EATER","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"FATIMA_LOTUS_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SERGEANT_GRONIA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L37_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"곤란하군. 내가 잠망경의 가동 범위를 벗어나면 우물과 연결된 낚싯대가 가동을 멈출 걸세.","JPN":"困ったな。私が潜望鏡の可動範囲から離れると、井戸と繋がっている釣り竿が止まってしまう。","ENG":"This isn't good. If I leave the Periscope's range of motion, the Fishing Rod connected to the Well will stop working as Well.","TWN":"真是麻煩啊。如果我離開了潛望鏡的有效範圍，連接在井裡的釣魚竿就會停止運作。"},"stage":{"bg":"COUNTERSIDE_BASE","bgm":"THEMA_DIVE_EATER","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"FATIMA_LOTUS_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SERGEANT_GRONIA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L38_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"그렇게 되면 패러독스를 구조할 타이밍도 놓치게 되겠지.","JPN":"そうなるとパラドックスを助けるタイミングを逃すことになるだろう。","ENG":"Then, we won't be there to rescue Paradox at the right time.","TWN":"那樣的話，就會錯過營救悖論的時機了。"},"stage":{"bg":"COUNTERSIDE_BASE","bgm":"THEMA_DIVE_EATER","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"FATIMA_LOTUS_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SERGEANT_GRONIA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L39_1","type":"dialog","speaker":"FATIMA_LOTUS_NULL_NULL","text":{"KOREA":"잠시 실례하겠습니다.","JPN":"少し失礼いたします。","ENG":"Excuse me.","TWN":"打擾了，請稍等。"},"stage":{"bg":"COUNTERSIDE_BASE","bgm":"THEMA_DIVE_EATER","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"FATIMA_LOTUS_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"SERGEANT_GRONIA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L41_1","type":"dialog","speaker":"FATIMA_LOTUS_NULL_NULL","text":{"KOREA":"흡-!!","JPN":"ふんっ！！","ENG":"Hmpf!","TWN":"呵——！！"},"stage":{"bg":"COUNTERSIDE_BASE","bgm":"THEMA_DIVE_EATER","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"sfx":"FX_COMBAT_ALL_MAGIC_SPELL_ICE"},{"id":"L44_1","type":"dialog","speaker":"SERGEANT_GRONIA_NULL_NULL","text":{"KOREA":"파티마 씨가 지면을 통째로 얼렸어요.","JPN":"ファティマさんが地面を凍らせました。","ENG":"Miss Fatima just froze the entire ground.","TWN":"法蒂瑪把地面整個凍住了。"},"stage":{"bg":"COUNTERSIDE_BASE","bgm":"THEMA_DIVE_EATER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SERGEANT_GRONIA_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L45_1","type":"dialog","speaker":"SERGEANT_GRONIA_NULL_NULL","text":{"KOREA":"이러면 안전하겠는데요?","JPN":"これで安全ですね。","ENG":"I guess it'll be safe now, right?","TWN":"這樣就安全了吧？"},"stage":{"bg":"COUNTERSIDE_BASE","bgm":"THEMA_DIVE_EATER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SERGEANT_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L46_1","type":"dialog","speaker":"FATIMA_LOTUS_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"COUNTERSIDE_BASE","bgm":"THEMA_DIVE_EATER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"FATIMA_LOTUS_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L48_1","type":"dialog","speaker":"SERGEANT_GRONIA_NULL_NULL","text":{"KOREA":"어라? 아래쪽에서 뭔가 끓는 듯한 소리가…?","JPN":"あれ？　下の方から何か音が……？","ENG":"Huh? I hear something boiling underneath us...","TWN":"咦？下面好像有什麼在沸騰的聲音……？"},"stage":{"bg":"COUNTERSIDE_BASE","bgm":"THEMA_DIVE_EATER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"FATIMA_LOTUS_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_COMBAT_ALL_SWING_ICE_SMALL"},{"id":"L3_1","type":"dialog","speaker":"FATIMA_LOTUS_NULL_NULL","text":{"KOREA":"…총탄?","JPN":"……銃弾？","ENG":"...A bullet?","TWN":"……是子彈？"},"stage":{"bg":"COUNTERSIDE_BASE","bgm":"THEMA_DIVE_EATER","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"FATIMA_LOTUS_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":null}}},{"id":"L4_1","type":"dialog","speaker":"SERGEANT_GRONIA_NULL_NULL","text":{"KOREA":"얼음을 부수고 나왔어?","JPN":"氷を砕いて出てきた？","ENG":"It broke through the ice?","TWN":"哇！冰被打碎了？"},"stage":{"bg":"COUNTERSIDE_BASE","bgm":"THEMA_DIVE_EATER","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"FATIMA_LOTUS_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"SERGEANT_GRONIA_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L10_1","type":"dialog","speaker":"FATIMA_LOTUS_NULL_NULL","text":{"KOREA":"저건… 북방합의체의 병사들입니다.","JPN":"あれは……北方合意体の兵士たちです。","ENG":"Those... are the Northern Union soldiers.","TWN":"那是……北方和議會的士兵。"},"stage":{"bg":"COUNTERSIDE_BASE","bgm":"THEMA_DIVE_EATER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SOLDIER_DOLL_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"FATIMA_LOTUS_NULL_NULL","text":{"KOREA":"아무 것도 없는 땅에서 군대가 나타나다니. 합의체의 기술력은 확실히 특이하군요.","JPN":"何もなかった地面から軍隊が現れるとは……合意体の技術力は確かに独特ですね。","ENG":"Making an army appear from out of nowhere. The Northern Union's technology is definitely unique.","TWN":"在空無一人的地方出現了軍隊，北方和議會的技術確實獨特。"},"stage":{"bg":"COUNTERSIDE_BASE","bgm":"THEMA_DIVE_EATER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"FATIMA_LOTUS_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"SERGEANT_GRONIA_NULL_NULL","text":{"KOREA":"저 사람들… 숨소리가 안 들려요.","JPN":"あの人たち……呼吸をしてませんね。","ENG":"Those people... I can't hear them breathe.","TWN":"那些人……我聽不到呼吸聲。"},"stage":{"bg":"COUNTERSIDE_BASE","bgm":"THEMA_DIVE_EATER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SERGEANT_GRONIA_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"SERGEANT_GRONIA_NULL_NULL","text":{"KOREA":"이전에 봤던 일반 병사들과 분위기도 다르고요.","JPN":"前に見た一般兵士たちと雰囲気も違います。","ENG":"And they look different from the regular soldiers we saw before.","TWN":"和之前見過的普通士兵的感覺也不一樣……"},"stage":{"bg":"COUNTERSIDE_BASE","bgm":"THEMA_DIVE_EATER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SERGEANT_GRONIA_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"미안하지만 방해받지 않을 시간이 필요하네.","JPN":"悪いが、誰にも邪魔されない時間が必要だ。","ENG":"I'm sorry to ask, but I will need some uninterrupted time.","TWN":"很抱歉，我需要一段不被打擾的時間。"},"stage":{"bg":"COUNTERSIDE_BASE","bgm":"THEMA_DIVE_EATER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"FATIMA_LOTUS_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"도와줄 수 있겠나?","JPN":"助けてくれないかね？","ENG":"Will you help me?","TWN":"可以幫我嗎？"},"stage":{"bg":"COUNTERSIDE_BASE","bgm":"THEMA_DIVE_EATER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"FATIMA_LOTUS_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"FATIMA_LOTUS_NULL_NULL","text":{"KOREA":"최대한 저지는 해보겠지만…","JPN":"なるべく阻止してみますが……","ENG":"I'll try my best to stop them, but...","TWN":"我會盡力阻止他們的……"},"stage":{"bg":"COUNTERSIDE_BASE","bgm":"THEMA_DIVE_EATER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"FATIMA_LOTUS_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"FATIMA_LOTUS_NULL_NULL","text":{"KOREA":"상황이 여의치 않아질 경우, 관리자님의 대피를 최우선으로 하겠습니다.","JPN":"撤退を余儀なくされた場合は、最高管理者の避難を最優先とします。","ENG":"if our situation worsens, I will prioritize your evacuation, Administrator.","TWN":"但如果情況不妙，我會優先協助管理者撤離。"},"stage":{"bg":"COUNTERSIDE_BASE","bgm":"THEMA_DIVE_EATER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"FATIMA_LOTUS_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"그럼 부탁하지.","JPN":"では、頼む。","ENG":"Thank you.","TWN":"那就拜託你了。"},"stage":{"bg":"COUNTERSIDE_BASE","bgm":"THEMA_DIVE_EATER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"FATIMA_LOTUS_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"SOLOVEY_ADMIN_NULL_NULL","text":{"KOREA":"다시… 여기까지 돌아왔네요.","JPN":"また……ここに戻ってきましたね。","ENG":"We're... back here again.","TWN":"又……回到了這裡呢。"},"stage":{"bg":"SKY","bgm":"CUTSCEN_FOREST_LOOP","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SOLOVEY_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"SOLOVEY_ADMIN_NULL_NULL","text":{"KOREA":"전 준비됐어요, 패리.","JPN":"私は準備できました。パリー。","ENG":"I'm ready, Parry.","TWN":"我準備好了，悖悖。"},"stage":{"bg":"SKY","bgm":"CUTSCEN_FOREST_LOOP","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SOLOVEY_ADMIN_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"WRITER_TIME_NULL_NULL","text":{"KOREA":"조심해라.","JPN":"気をつけて。","ENG":"Be careful.","TWN":"要小心啊。"},"stage":{"bg":"SKY","bgm":"CUTSCEN_FOREST_LOOP","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"WRITER_TIME_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"WRITER_TIME_NULL_NULL","text":{"KOREA":"분명 그것과 다시 마주치게 될 테니까.","JPN":"絶対、またあれに会うことになる。","ENG":"You'll be running into that thing again.","TWN":"我們肯定會再次遇到它的。"},"stage":{"bg":"SKY","bgm":"CUTSCEN_FOREST_LOOP","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"WRITER_TIME_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"SOLOVEY_ADMIN_NULL_NULL","text":{"KOREA":"…네!","JPN":"……はい！","ENG":"...Okay!","TWN":"……好的！"},"stage":{"bg":"SKY","bgm":"CUTSCEN_FOREST_LOOP","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SOLOVEY_ADMIN_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"SOLOVEY_ADMIN_NULL_NULL","text":{"KOREA":"또 다시… 어머니의 익숙한 꽃향기…","JPN":"まただ……お母さんの香り……","ENG":"I smell it again... Mother's floral scent.","TWN":"又一次……媽媽身上熟悉的花香……"},"stage":{"bg":"BLACK","bgm":"CUTSCEN_FOREST_LOOP","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SOLOVEY_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"SOLOVEY_ADMIN_NULL_NULL","text":{"KOREA":"안뜰로 다가갈수록 짙어지고 있어.","JPN":"中庭に近づくほど香りが濃くなっていく。","ENG":"It's getting stronger the closer I get to the inner yard.","TWN":"越靠近庭院，氣味就越發清晰。"},"stage":{"bg":"BLACK","bgm":"CUTSCEN_FOREST_LOOP","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SOLOVEY_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L34_1","type":"dialog","speaker":"SOLOVEY_ADMIN_NULL_NULL","text":{"KOREA":"솔직히… 지금도 겁나지 않는 건 아냐.","JPN":"正直……怖い。","ENG":"Honestly... I'd be lying if I said I wasn't scared.","TWN":"說實話……現在也不是完全不怕。"},"stage":{"bg":"BLACK","bgm":"CUTSCEN_FOREST_LOOP","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SOLOVEY_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L35_1","type":"dialog","speaker":"SOLOVEY_ADMIN_NULL_NULL","text":{"KOREA":"어머니의 목소리를 들으면… 또 마음이 흔들릴 지도 몰라.","JPN":"お母さんの声を聞いたら……また心が揺れてしまうかもしれない。","ENG":"I might even have doubts again... upon hearing Mother's voice.","TWN":"聽到媽媽的聲音……也許還會再次動搖。"},"stage":{"bg":"BLACK","bgm":"CUTSCEN_FOREST_LOOP","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SOLOVEY_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L38_1","type":"dialog","speaker":"SOLOVEY_ADMIN_NULL_NULL","text":{"KOREA":"하지만 견뎌야 해.","JPN":"でも耐えないと。","ENG":"But I must endure it.","TWN":"不……我可以忍住的。"},"stage":{"bg":"SWORDGRAVE_STAR","bgm":"CUTSCEN_FOREST_LOOP","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L39_1","type":"dialog","speaker":"SOLOVEY_ADMIN_NULL_NULL","text":{"KOREA":"어머니 덕분에 알게 된 미래의 소중함을…","JPN":"お母さんのおかげでわかった、未来の大切さ……","ENG":"Because I want to protect...","TWN":"因為媽媽，我才懂得了未來的珍貴……"},"stage":{"bg":"SWORDGRAVE_STAR","bgm":"CUTSCEN_FOREST_LOOP","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L44_1","type":"dialog","speaker":"SOLOVEY_ADMIN_NULL_NULL","text":{"KOREA":"…내 손으로 지켜내고 싶으니까.","JPN":"……その未来を、この手で守りたいから。","ENG":"...the preciousness of the future that I learned from Mother.","TWN":"現在……我想親手守護它。"},"stage":{"bg":"COUNTERSIDE_GARDEN","bgm":"CUTSCEN_FOREST_LOOP","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SOLOVEY_ADMIN_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L1_1","type":"dialog","speaker":"SERGEANT_GRONIA_NULL_NULL","text":{"KOREA":"윽…?!","JPN":"うっ……！？","ENG":"Ngh...?!","TWN":"呃……？！"},"stage":{"bg":"COUNTERSIDE_BASE_NIGHT","bgm":"THEMA_SA_COMMANDER_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L2_1","type":"dialog","speaker":"SERGEANT_GRONIA_NULL_NULL","text":{"KOREA":"상황이 좋지 않네요.","JPN":"まずい状況です。","ENG":"This isn't looking good.","TWN":"情況好像很不妙……"},"stage":{"bg":"COUNTERSIDE_BASE_NIGHT","bgm":"THEMA_SA_COMMANDER_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":{"char_id":"SERGEANT_GRONIA_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L3_1","type":"dialog","speaker":"SERGEANT_GRONIA_NULL_NULL","text":{"KOREA":"적 수가 전혀 줄어들지 않아요.","JPN":"敵の数がまったく減ってません。","ENG":"Their numbers aren't decreasing at all.","TWN":"敵人的數量完全沒有減少。"},"stage":{"bg":"COUNTERSIDE_BASE_NIGHT","bgm":"THEMA_SA_COMMANDER_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":{"char_id":"SERGEANT_GRONIA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L4_1","type":"dialog","speaker":"SERGEANT_GRONIA_NULL_NULL","text":{"KOREA":"공격할 때마다 마치 마시멜로처럼 녹아서… 쓰러트렸다는 느낌도 안 들고요.","JPN":"攻撃するたびにマシュマロみたいに溶けて……手ごたえがありません。","ENG":"And it doesn't feel like I defeated them... because they melt like marshmallows whenever I attack one of them.","TWN":"而且每次攻擊就像打在棉花上一樣……完全沒有擊倒的感覺……"},"stage":{"bg":"COUNTERSIDE_BASE_NIGHT","bgm":"THEMA_SA_COMMANDER_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":{"char_id":"SERGEANT_GRONIA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L5_1","type":"dialog","speaker":"FATIMA_LOTUS_NULL_NULL","text":{"KOREA":"이대로 소모전이 계속되면 불리해지겠군요.","JPN":"このまま消耗戦が続くと、こちらが不利になります。","ENG":"We'll be at a disadvantage if this attrition warfare continues.","TWN":"這樣繼續消耗下去的話，我們會處於劣勢。"},"stage":{"bg":"COUNTERSIDE_BASE_NIGHT","bgm":"THEMA_SA_COMMANDER_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"FATIMA_LOTUS_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"SERGEANT_GRONIA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L6_1","type":"dialog","speaker":"SERGEANT_GRONIA_NULL_NULL","text":{"KOREA":"포위망을 유지하면서 최소한의 병력으로 저흴 압박하고 있어요.","JPN":"向こうは包囲網を保ちながら、最低限の兵力で私たちを威嚇してます。","ENG":"They have us surrounded and they're pressuring us with only the minimum number of units necessary.","TWN":"他們在保持包圍網的同時，用最少的兵力壓制我們。"},"stage":{"bg":"COUNTERSIDE_BASE_NIGHT","bgm":"THEMA_SA_COMMANDER_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"FATIMA_LOTUS_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"SERGEANT_GRONIA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L7_1","type":"dialog","speaker":"SERGEANT_GRONIA_NULL_NULL","text":{"KOREA":"마치… 저희를 제압할 생각이 없는 것 같아요.","JPN":"まるで……完全に私たちを制圧する気はない様子です。","ENG":"It's as if... they have no intention of defeating us.","TWN":"好像……他們並不打算殺死我們。"},"stage":{"bg":"COUNTERSIDE_BASE_NIGHT","bgm":"THEMA_SA_COMMANDER_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"FATIMA_LOTUS_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"SERGEANT_GRONIA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L9_1","type":"dialog","speaker":null,"text":{"KOREA":"맞아.","JPN":"そうだ。","ENG":"That's right.","TWN":"沒錯。"},"stage":{"bg":"COUNTERSIDE_BASE_NIGHT","bgm":"THEMA_SA_COMMANDER_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"FATIMA_LOTUS_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"SERGEANT_GRONIA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L11_1","type":"dialog","speaker":null,"text":{"KOREA":"우리 목적은 당신들을 처리하는 게 아니라 발만 묶어두는 거니까.","JPN":"私たちの目的は君たちを倒すことではなく、足止めすることだから。","ENG":"Our objective is not taking you down, but keeping you tied up.","TWN":"我們的目的不是擊斃，而是暫時限制你們。"},"stage":{"bg":"COUNTERSIDE_BASE_NIGHT","bgm":"THEMA_SA_COMMANDER_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"FATIMA_LOTUS_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"SERGEANT_GRONIA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L12_1","type":"dialog","speaker":"SERGEANT_GRONIA_NULL_NULL","text":{"KOREA":"당신은…?","JPN":"あなたは……？","ENG":"You're...?","TWN":"你是……？"},"stage":{"bg":"COUNTERSIDE_BASE_NIGHT","bgm":"THEMA_SA_COMMANDER_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"FATIMA_LOTUS_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"SERGEANT_GRONIA_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L14_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"펠릭스…","JPN":"フェリックス……","ENG":"Felix...","TWN":"緋莉克絲……"},"stage":{"bg":"COUNTERSIDE_BASE_NIGHT","bgm":"THEMA_SA_COMMANDER_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"FATIMA_LOTUS_NULL_NULL","face":"UNIT_SERIOUS"},"C":{"char_id":"COMMANDER_UNION_NULL_NULL","face":"UNIT_IDLE"},"R":{"char_id":"SERGEANT_GRONIA_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L15_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"우릴 도운 건, 이런 식으로 뒤통수를 칠 목적이었나?","JPN":"私たちを助けたのは、こうやって不意をつくためだったのか？","ENG":"Did you only help us so that you could stab us in the back like this?","TWN":"你幫了我們，是為了再出賣我們一次嗎？"},"stage":{"bg":"COUNTERSIDE_BASE_NIGHT","bgm":"THEMA_SA_COMMANDER_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"FATIMA_LOTUS_NULL_NULL","face":"UNIT_SERIOUS"},"C":{"char_id":"COMMANDER_UNION_NULL_NULL","face":"UNIT_IDLE"},"R":{"char_id":"SERGEANT_GRONIA_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L16_1","type":"dialog","speaker":"COMMANDER_UNION_NULL_NULL","text":{"KOREA":"나도 명령을 받는 입장이라 어쩔 수 없어.","JPN":"私も命令される側なので、仕方ない。","ENG":"I had no choice. I have to follow orders.","TWN":"我也是奉命行事，沒辦法。"},"stage":{"bg":"COUNTERSIDE_BASE_NIGHT","bgm":"THEMA_SA_COMMANDER_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"FATIMA_LOTUS_NULL_NULL","face":"UNIT_SERIOUS"},"C":{"char_id":"COMMANDER_UNION_NULL_NULL","face":"UNIT_IDLE"},"R":{"char_id":"SERGEANT_GRONIA_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L17_1","type":"dialog","speaker":"COMMANDER_UNION_NULL_NULL","text":{"KOREA":"관리국 최고 등급의 아티팩트 두 개가 한 자리에 모여있다는 정보가 상부의 귀에 들어갔거든.","JPN":"管理局最高ランクのアーティファクトが2つも1か所に揃っているという情報が、上層部の耳に入ってな。","ENG":"Intel about two of the Administration's strongest Artifacts being here reached the higher-ups, you see.","TWN":"管理局最高等級的兩件神器齊聚一堂，這種事情恰巧被上層知道了。"},"stage":{"bg":"COUNTERSIDE_BASE_NIGHT","bgm":"THEMA_SA_COMMANDER_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"FATIMA_LOTUS_NULL_NULL","face":"UNIT_SERIOUS"},"C":{"char_id":"COMMANDER_UNION_NULL_NULL","face":"UNIT_PRIDE"},"R":{"char_id":"SERGEANT_GRONIA_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L18_1","type":"dialog","speaker":"SERGEANT_GRONIA_NULL_NULL","text":{"KOREA":"말도 안돼. 북방합의체가 그 정보를 어떻게…?","JPN":"そんな……北方合意体がどうやってその情報を……？","ENG":"That's impossible. How did the Northern Union get that information...?","TWN":"這不可能。北方和議會怎麼會知道這些資訊……？"},"stage":{"bg":"COUNTERSIDE_BASE_NIGHT","bgm":"THEMA_SA_COMMANDER_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"FATIMA_LOTUS_NULL_NULL","face":"UNIT_SERIOUS"},"C":{"char_id":"COMMANDER_UNION_NULL_NULL","face":"UNIT_PRIDE"},"R":{"char_id":"SERGEANT_GRONIA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L19_1","type":"dialog","speaker":"COMMANDER_UNION_NULL_NULL","text":{"KOREA":"왜일까? 어쩌면 조직 내부에 새는 구멍이 있을지도 모르지.","JPN":"さあ？　もしかしたら、組織内の誰かが流しているかもな。","ENG":"How do you think? Maybe you have a leak inside the organization.","TWN":"為什麼呢？也許你們組織內部也有洩密的漏洞吧。"},"stage":{"bg":"COUNTERSIDE_BASE_NIGHT","bgm":"THEMA_SA_COMMANDER_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"FATIMA_LOTUS_NULL_NULL","face":"UNIT_SERIOUS"},"C":{"char_id":"COMMANDER_UNION_NULL_NULL","face":"UNIT_IDLE"},"R":{"char_id":"SERGEANT_GRONIA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L20_1","type":"dialog","speaker":"FATIMA_LOTUS_NULL_NULL","text":{"KOREA":"협잡질이라니. 영웅이란 명성에 어울리지 않는 얕은 수법이군요, 펠릭스.","JPN":"仲違いをさせるとは、英雄という名に相応しくない浅い作戦ですね。フェリックス。","ENG":"You tricked us. That's a shallow tactic that doesn't befit your reputation as a hero, Felix.","TWN":"你在耍陰謀詭計嗎？這可不是英雄應有的名聲，緋莉克絲。"},"stage":{"bg":"COUNTERSIDE_BASE_NIGHT","bgm":"THEMA_SA_COMMANDER_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"FATIMA_LOTUS_NULL_NULL","face":"UNIT_HATE"},"C":{"char_id":"COMMANDER_UNION_NULL_NULL","face":"UNIT_IDLE"},"R":{"char_id":"SERGEANT_GRONIA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L21_1","type":"dialog","speaker":"COMMANDER_UNION_NULL_NULL","text":{"KOREA":"후후, 의심할 여지는 이미 충분하지 않아?","JPN":"ふふ、疑う余地は十分あると思うが？","ENG":"Fu fuu. Didn't I already give you enough reason to doubt that?","TWN":"呵呵，我應該已經給了你們懷疑我的理由了吧？"},"stage":{"bg":"COUNTERSIDE_BASE_NIGHT","bgm":"THEMA_SA_COMMANDER_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"FATIMA_LOTUS_NULL_NULL","face":"UNIT_HATE"},"C":{"char_id":"COMMANDER_UNION_NULL_NULL","face":"UNIT_LAUGH"},"R":{"char_id":"SERGEANT_GRONIA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L22_1","type":"dialog","speaker":"COMMANDER_UNION_NULL_NULL","text":{"KOREA":"챔버의 시니어만 하더라도 이미 당신들 몰래 우리와 협력하고 있었는걸?","JPN":"チェンバーのシニアだって、既に君たちには内密で私たちと協力していたんだぞ？","ENG":"Even Chamber's Senior was conspiring with us behind your backs.","TWN":"而且，就連強巴的Senior也已經在暗中與我們合作了呢？"},"stage":{"bg":"COUNTERSIDE_BASE_NIGHT","bgm":"THEMA_SA_COMMANDER_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"FATIMA_LOTUS_NULL_NULL","face":"UNIT_HATE"},"C":{"char_id":"COMMANDER_UNION_NULL_NULL","face":"UNIT_IDLE"},"R":{"char_id":"SERGEANT_GRONIA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L23_1","type":"dialog","speaker":"FATIMA_LOTUS_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"COUNTERSIDE_BASE_NIGHT","bgm":"THEMA_SA_COMMANDER_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"FATIMA_LOTUS_NULL_NULL","face":"UNIT_SURPRISE"},"C":{"char_id":"COMMANDER_UNION_NULL_NULL","face":"UNIT_IDLE"},"R":{"char_id":"SERGEANT_GRONIA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L25_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"그럴싸한 이야기군.","JPN":"それっぽい話だな。","ENG":"Sounds plausible.","TWN":"聽起來有理有據。"},"stage":{"bg":"COUNTERSIDE_BASE_NIGHT","bgm":"THEMA_SA_COMMANDER_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"FATIMA_LOTUS_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"COMMANDER_UNION_NULL_NULL","face":"UNIT_IDLE"},"R":{"char_id":"SERGEANT_GRONIA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L26_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"그렇다면 잭슨은 자네들과 무슨 협력을 하고 있었던 거지?","JPN":"では、ジャクソンは君たちに何を協力していた？","ENG":"So, what was Jackson cooperating on with you exactly?","TWN":"那麼，傑森和你們在合作些什麼呢？"},"stage":{"bg":"COUNTERSIDE_BASE_NIGHT","bgm":"THEMA_SA_COMMANDER_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"FATIMA_LOTUS_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"COMMANDER_UNION_NULL_NULL","face":"UNIT_IDLE"},"R":{"char_id":"SERGEANT_GRONIA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L27_1","type":"dialog","speaker":"FATIMA_LOTUS_NULL_NULL","text":{"KOREA":"귀담아 들으실 필요 없습니다, 관리자님. 저 자는 그저 저희를 농락하려는 거니까요.","JPN":"耳を貸す必要はありません、最高管理者様。あの者は私たちを混乱させようとしているだけです。","ENG":"Don't listen to them, Administrator. They are just trying to get in our heads.","TWN":"你不必在意，管理者。那傢伙只是想戲弄我們而已。"},"stage":{"bg":"COUNTERSIDE_BASE_NIGHT","bgm":"THEMA_SA_COMMANDER_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"FATIMA_LOTUS_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"COMMANDER_UNION_NULL_NULL","face":"UNIT_IDLE"},"R":{"char_id":"SERGEANT_GRONIA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L28_1","type":"dialog","speaker":"COMMANDER_UNION_NULL_NULL","text":{"KOREA":"잭슨은 진리 연구부의 열렬한 후원자였어. 그 지원 덕분에 우리도 큰 진전을 이룰 수 있었지.","JPN":"ジャクソンは真理研究部の熱烈な支援者だった。おかげで私たちも大きな進歩を成し遂げることができたよ。","ENG":"Jackson was an ardent supporter of the Veritas Research Department. We made significant progress thanks to his support.","TWN":"傑森是真理研究部的熱心支持者。多虧了他的贊助，我們的項目才能取得巨大的進展。"},"stage":{"bg":"COUNTERSIDE_BASE_NIGHT","bgm":"THEMA_SA_COMMANDER_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"FATIMA_LOTUS_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"COMMANDER_UNION_NULL_NULL","face":"UNIT_DESPAIR"},"R":{"char_id":"SERGEANT_GRONIA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L29_1","type":"dialog","speaker":"COMMANDER_UNION_NULL_NULL","text":{"KOREA":"후원에 대한 감사의 표시로 우리가 만들어낸 성공작 하나를 선물하기도 했는데…","JPN":"お礼として、私たちが作り出した作品を1つ贈ったこともあるが……","ENG":"And as a token of our gratitude, we gifted him one of our successful works...","TWN":"為了表示對他的感謝，我們還他別贈送了一件我們成功的作品……"},"stage":{"bg":"COUNTERSIDE_BASE_NIGHT","bgm":"THEMA_SA_COMMANDER_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"FATIMA_LOTUS_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"COMMANDER_UNION_NULL_NULL","face":"UNIT_IDLE"},"R":{"char_id":"SERGEANT_GRONIA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L30_1","type":"dialog","speaker":"COMMANDER_UNION_NULL_NULL","text":{"KOREA":"그게 누구인진 당신들도 이제 짐작이 갈 거야.","JPN":"それが誰なのかは言わずともわかるだろう。","ENG":"I guess you already know who I'm talking about.","TWN":"那個人是誰，你們現在應該也能猜到了。"},"stage":{"bg":"COUNTERSIDE_BASE_NIGHT","bgm":"THEMA_SA_COMMANDER_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"FATIMA_LOTUS_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"COMMANDER_UNION_NULL_NULL","face":"UNIT_LAUGH"},"R":{"char_id":"SERGEANT_GRONIA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L31_1","type":"dialog","speaker":"FATIMA_LOTUS_NULL_NULL","text":{"KOREA":"선물이라고…?","JPN":"贈り物……？","ENG":"A gift...?","TWN":"禮物……？"},"stage":{"bg":"COUNTERSIDE_BASE_NIGHT","bgm":"THEMA_SA_COMMANDER_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"FATIMA_LOTUS_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"COMMANDER_UNION_NULL_NULL","face":"UNIT_LAUGH"},"R":{"char_id":"SERGEANT_GRONIA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L33_1","type":"dialog","speaker":null,"text":{"KOREA":"…예니카 시로코바.","JPN":"……イェニカ・シロコバ。","ENG":"...Yanikka Shirokova.","TWN":"……耶妮卡·西羅科娃。"},"stage":{"bg":"COUNTERSIDE_BASE_NIGHT","bgm":"THEMA_SA_COMMANDER_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"FATIMA_LOTUS_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"COMMANDER_UNION_NULL_NULL","face":"UNIT_LAUGH"},"R":{"char_id":"SERGEANT_GRONIA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L34_1","type":"dialog","speaker":"SERGEANT_GRONIA_NULL_NULL","text":{"KOREA":"예니카 씨…?","JPN":"イェニカさん……？","ENG":"Miss Yanikka...?","TWN":"耶妮卡……？"},"stage":{"bg":"COUNTERSIDE_BASE_NIGHT","bgm":"THEMA_SA_COMMANDER_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"FATIMA_LOTUS_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"COMMANDER_UNION_NULL_NULL","face":"UNIT_LAUGH"},"R":{"char_id":"SERGEANT_GRONIA_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L35_1","type":"dialog","speaker":"SERGEANT_GRONIA_NULL_NULL","text":{"KOREA":"그 사람이… 북방합의체의 선물…?","JPN":"あの人が……北方合意体からの贈り物……？","ENG":"She is... the gift from the Northern Union...?","TWN":"那個人……是北方和議會的禮物……？"},"stage":{"bg":"COUNTERSIDE_BASE_NIGHT","bgm":"THEMA_SA_COMMANDER_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"FATIMA_LOTUS_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"COMMANDER_UNION_NULL_NULL","face":"UNIT_LAUGH"},"R":{"char_id":"SERGEANT_GRONIA_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L36_1","type":"dialog","speaker":"COMMANDER_UNION_NULL_NULL","text":{"KOREA":"응, 맞아.","JPN":"そうだ。","ENG":"Yes, that's right.","TWN":"嗯，沒錯。"},"stage":{"bg":"COUNTERSIDE_BASE_NIGHT","bgm":"THEMA_SA_COMMANDER_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"FATIMA_LOTUS_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"COMMANDER_UNION_NULL_NULL","face":"UNIT_IDLE"},"R":{"char_id":"SERGEANT_GRONIA_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L37_1","type":"dialog","speaker":"COMMANDER_UNION_NULL_NULL","text":{"KOREA":"창백한 달의 연구를 통해 만든 우리 작품이지.","JPN":"青白い月の研究研究から作り出した私たちの作品さ。","ENG":"She is the result of our research on the Pale Moon.","TWN":"她是我們研究蒼月的實驗成果。"},"stage":{"bg":"COUNTERSIDE_BASE_NIGHT","bgm":"THEMA_SA_COMMANDER_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"FATIMA_LOTUS_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"COMMANDER_UNION_NULL_NULL","face":"UNIT_IDLE"},"R":{"char_id":"SERGEANT_GRONIA_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L40_1","type":"dialog","speaker":"FATIMA_LOTUS_NULL_NULL","text":{"KOREA":"그런 중요한 존재를 관리국의 조력자에게 순순히 넘겼다고 말하는 건가?","JPN":"そんな重要な存在を、管理局の協力者に渡したというのですか？","ENG":"Are you meaning to say that you handed over such an important result to someone of the Administration?","TWN":"你是說把那樣重要的研究成果交給了管理局當助手嗎？"},"stage":{"bg":"COUNTERSIDE_BASE_NIGHT","bgm":"THEMA_SA_COMMANDER_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"FATIMA_LOTUS_NULL_NULL","face":"UNIT_SERIOUS"},"C":{"char_id":"COMMANDER_UNION_NULL_NULL","face":"UNIT_IDLE"},"R":{"char_id":"SERGEANT_GRONIA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L42_1","type":"dialog","speaker":"COMMANDER_UNION_NULL_NULL","text":{"KOREA":"태양이 달을 빛나게 한다고 해서, 태양이 빛을 잃는 건 아니지.","JPN":"太陽が月に光を与えるからと、太陽が光を失うわけではない。","ENG":"Just because the sun makes the moon shine, that doesn't mean that the sun will lose its shine.","TWN":"太陽賦予了月亮光輝，但它並不會因此而失去光芒。"},"stage":{"bg":"COUNTERSIDE_BASE_NIGHT","bgm":"THEMA_SA_COMMANDER_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"FATIMA_LOTUS_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"COMMANDER_UNION_NULL_NULL","face":"UNIT_DESPAIR"},"R":{"char_id":"SERGEANT_GRONIA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L43_1","type":"dialog","speaker":"COMMANDER_UNION_NULL_NULL","text":{"KOREA":"북방합의체가 가진 기술력은 그 아이 하나를 만들기 위해 존재하는 게 아니니까.","JPN":"北方合意体の技術力は、あの子1人を作るために存在しているわけでないという意味だ。","ENG":"The Northern Union's technological capabilities do not exist to merely create that one child.","TWN":"同理，北方和議會的技術並不是為了製造那個女孩而存在的。"},"stage":{"bg":"COUNTERSIDE_BASE_NIGHT","bgm":"THEMA_SA_COMMANDER_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"FATIMA_LOTUS_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"COMMANDER_UNION_NULL_NULL","face":"UNIT_IDLE"},"R":{"char_id":"SERGEANT_GRONIA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L45_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"그 아이의 행방이 자네들 앞길을 막는 걸림돌이 된다 해도 말인가?","JPN":"結果的にあの子が君たちの行く手を阻むことになるとしてもか？","ENG":"Even if that one child becomes an obstacle in your path?","TWN":"就算那個孩子最後會成為你們前進的絆腳石也無所謂嗎？"},"stage":{"bg":"COUNTERSIDE_BASE_NIGHT","bgm":"THEMA_SA_COMMANDER_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"FATIMA_LOTUS_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"COMMANDER_UNION_NULL_NULL","face":"UNIT_IDLE"},"R":{"char_id":"SERGEANT_GRONIA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L46_1","type":"dialog","speaker":"COMMANDER_UNION_NULL_NULL","text":{"KOREA":"후훗, 인과응보 또한 우리가 감내해야 할 부산물이야.","JPN":"ふふ、因果応報もまた、私たちが背負うべき副産物。","ENG":"Haha, retribution is merely a byproduct we must endure.","TWN":"呵呵，因果報應也是我們必須承受的副作用。"},"stage":{"bg":"COUNTERSIDE_BASE_NIGHT","bgm":"THEMA_SA_COMMANDER_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"FATIMA_LOTUS_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"COMMANDER_UNION_NULL_NULL","face":"UNIT_IDLE"},"R":{"char_id":"SERGEANT_GRONIA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L47_1","type":"dialog","speaker":"COMMANDER_UNION_NULL_NULL","text":{"KOREA":"익숙하지 않아?","JPN":"君もわかるだろう？","ENG":"Doesn't this all sound familiar?","TWN":"不覺得熟悉嗎？"},"stage":{"bg":"COUNTERSIDE_BASE_NIGHT","bgm":"THEMA_SA_COMMANDER_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"FATIMA_LOTUS_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"COMMANDER_UNION_NULL_NULL","face":"UNIT_PRIDE"},"R":{"char_id":"SERGEANT_GRONIA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L48_1","type":"dialog","speaker":"COMMANDER_UNION_NULL_NULL","text":{"KOREA":"늑대 한 마리를 위해 모든 걸 희생한 당신이라면 이해해줄 거라 생각했는데.","JPN":"オオカミ1匹のためにすべてを犠牲にした君なら、わかってくれると思っていたが。","ENG":"I thought you'd understand, given that you sacrificed everything for one wolf.","TWN":"我以為你會理解，作為能夠為了一隻狼而犧牲一切的人。"},"stage":{"bg":"COUNTERSIDE_BASE_NIGHT","bgm":"THEMA_SA_COMMANDER_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"FATIMA_LOTUS_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"COMMANDER_UNION_NULL_NULL","face":"UNIT_IDLE"},"R":{"char_id":"SERGEANT_GRONIA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L50_1","type":"dialog","speaker":"SERGEANT_GRONIA_NULL_NULL","text":{"KOREA":"늑대? 그게 무슨 의미…?","JPN":"オオカミ？　それはどういう……？","ENG":"Wolf? What does that mean...?","TWN":"狼？那是什麼意思……？"},"stage":{"bg":"COUNTERSIDE_BASE_NIGHT","bgm":"THEMA_SA_COMMANDER_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"FATIMA_LOTUS_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"COMMANDER_UNION_NULL_NULL","face":"UNIT_IDLE"},"R":{"char_id":"SERGEANT_GRONIA_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L5_1","type":"dialog","speaker":"SERGEANT_GRONIA_NULL_NULL","text":{"KOREA":"저 괴물들은…?","JPN":"あの化け物たちは……？","ENG":"What are those monsters...?","TWN":"那些怪物是……？"},"stage":{"bg":"COUNTERSIDE_BASE_NIGHT","bgm":"THEMA_SA_COMMANDER_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"FATIMA_LOTUS_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"COMMANDER_UNION_NULL_NULL","face":"UNIT_IDLE"},"R":{"char_id":"SERGEANT_GRONIA_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L6_1","type":"dialog","speaker":"FATIMA_LOTUS_NULL_NULL","text":{"KOREA":"북방합의체와 함께 움직이던 그림자군요.","JPN":"北方合意体と共に動いていたシャドウですね。","ENG":"The Shadow that was with the Northern Union.","TWN":"與北方和議會一起行動的暗影。"},"stage":{"bg":"COUNTERSIDE_BASE_NIGHT","bgm":"THEMA_SA_COMMANDER_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"FATIMA_LOTUS_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"COMMANDER_UNION_NULL_NULL","face":"UNIT_IDLE"},"R":{"char_id":"SERGEANT_GRONIA_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L7_1","type":"dialog","speaker":"FATIMA_LOTUS_NULL_NULL","text":{"KOREA":"지난 번엔 침식체가 타깃이었지만, 이번엔 저희를 노릴 겁니다.","JPN":"前回のターゲットは侵食体でしたが、今回は私たちを狙ってくるでしょう。","ENG":"It targeted C.O.s last time, but it will come after us this time.","TWN":"上次的目標是侵蝕體，沒想到這次就盯上我們了。"},"stage":{"bg":"COUNTERSIDE_BASE_NIGHT","bgm":"THEMA_SA_COMMANDER_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"FATIMA_LOTUS_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"COMMANDER_UNION_NULL_NULL","face":"UNIT_IDLE"},"R":{"char_id":"SERGEANT_GRONIA_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L8_1","type":"dialog","speaker":"SERGEANT_GRONIA_NULL_NULL","text":{"KOREA":"이번엔 둘이네요. 하나가 끝이 아닐 줄이야.","JPN":"今回は2体ですね。まだもう1体いたとは……","ENG":"There are two of them this time. And I thought one was enough.","TWN":"這次是兩個啊……難道一個還不夠嗎……"},"stage":{"bg":"COUNTERSIDE_BASE_NIGHT","bgm":"THEMA_SA_COMMANDER_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"FATIMA_LOTUS_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"COMMANDER_UNION_NULL_NULL","face":"UNIT_IDLE"},"R":{"char_id":"SERGEANT_GRONIA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L11_1","type":"dialog","speaker":"COMMANDER_UNION_NULL_NULL","text":{"KOREA":"체르노보그.","JPN":"チェルノボーグ。","ENG":"Chernobog.","TWN":"申諾伯。"},"stage":{"bg":"COUNTERSIDE_BASE_NIGHT","bgm":"THEMA_SA_COMMANDER_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"FATIMA_LOTUS_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"COMMANDER_UNION_NULL_NULL","face":"UNIT_IDLE"},"R":{"char_id":"SERGEANT_GRONIA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L12_1","type":"dialog","speaker":"COMMANDER_UNION_NULL_NULL","text":{"KOREA":"오롯이 날 향한 맹목적인 충성심… 그 집착으로 빚어진 특별한 형제들이지.","JPN":"私への盲目的でまっすぐな忠誠心……執着ともいえる感情でできた特別な兄弟だ。","ENG":"They are Brothers... molded with the obsession of their unquestioned loyalty to me.","TWN":"他們是對我懷有單純而盲目的忠誠……因為這種執念而誕生的特殊的兄弟們。"},"stage":{"bg":"COUNTERSIDE_BASE_NIGHT","bgm":"THEMA_SA_COMMANDER_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"FATIMA_LOTUS_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"COMMANDER_UNION_NULL_NULL","face":"UNIT_IDLE"},"R":{"char_id":"SERGEANT_GRONIA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L13_1","type":"dialog","speaker":"COMMANDER_UNION_NULL_NULL","text":{"KOREA":"아직 프로토타입이라서 전술 데이터가 부족하거든.","JPN":"まだプロトタイプだから戦術データが足りなくてな。","ENG":"We lack tactical data on them since they are prototypes.","TWN":"因為還只是原型，所以戰術資料不足。"},"stage":{"bg":"COUNTERSIDE_BASE_NIGHT","bgm":"THEMA_SA_COMMANDER_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"FATIMA_LOTUS_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"COMMANDER_UNION_NULL_NULL","face":"UNIT_IDLE"},"R":{"char_id":"SERGEANT_GRONIA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L14_1","type":"dialog","speaker":"COMMANDER_UNION_NULL_NULL","text":{"KOREA":"당신들을 상대로 시험해보려고 하는데, 도와줄 거지?","JPN":"君たちを相手に試してみたいのだが、当然協力してくれるだろう？","ENG":"So, we're going to test them on you. You don't mind, do you?","TWN":"我想拿你們來試試，你們不會介意的，對吧？"},"stage":{"bg":"COUNTERSIDE_BASE_NIGHT","bgm":"THEMA_SA_COMMANDER_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"FATIMA_LOTUS_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"COMMANDER_UNION_NULL_NULL","face":"UNIT_PRIDE"},"R":{"char_id":"SERGEANT_GRONIA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L16_1","type":"dialog","speaker":"FATIMA_LOTUS_NULL_NULL","text":{"KOREA":"브레히트 양, 조심하십시오.","JPN":"ブレヒトさん、気をつけてください。","ENG":"Miss Brecht, be careful.","TWN":"布萊希特，請小心。"},"stage":{"bg":"COUNTERSIDE_BASE_NIGHT","bgm":"THEMA_SA_COMMANDER_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"FATIMA_LOTUS_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"COMMANDER_UNION_NULL_NULL","face":"UNIT_IDLE"},"R":{"char_id":"SERGEANT_GRONIA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L17_1","type":"dialog","speaker":"FATIMA_LOTUS_NULL_NULL","text":{"KOREA":"저 인간 형체는 껍데기일 뿐, 언제 돌변할지 모릅니다.","JPN":"あの人間の形はただの殻にすぎない。いつ豹変するかわかりません。","ENG":"Their human form is just a shell. You don't know when it will change.","TWN":"那個人類的形態只是外殼，請留意他會突然變異。"},"stage":{"bg":"COUNTERSIDE_BASE_NIGHT","bgm":"THEMA_SA_COMMANDER_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"FATIMA_LOTUS_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"COMMANDER_UNION_NULL_NULL","face":"UNIT_IDLE"},"R":{"char_id":"SERGEANT_GRONIA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L19_1","type":"dialog","speaker":"SERGEANT_GRONIA_NULL_NULL","text":{"KOREA":"알겠어요.","JPN":"わかりました。","ENG":"Got it.","TWN":"知道了。"},"stage":{"bg":"COUNTERSIDE_BASE_NIGHT","bgm":"THEMA_SA_COMMANDER_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":{"char_id":"SERGEANT_GRONIA_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L20_1","type":"dialog","speaker":"SERGEANT_GRONIA_NULL_NULL","text":{"KOREA":"파티마 씨도 조심하세요.","JPN":"ファティマさんも気をつけて。","ENG":"Miss Fatima, you be careful too.","TWN":"法蒂瑪……你也要小心……"},"stage":{"bg":"COUNTERSIDE_BASE_NIGHT","bgm":"THEMA_SA_COMMANDER_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":{"char_id":"SERGEANT_GRONIA_NULL_NULL","face":"UNIT_IDLE"}}}}]`);export{e as default};